mapper.select:
SELECT d.*
FROM iot_device d

    d.del_flag = 0

        AND d.device_name LIKE CONCAT('%',#{deviceName},'%')


        AND d.device_type = #{deviceType}


        AND d.status = #{status}




        AND EXISTS (
        SELECT 1 FROM iot_device_auth a

        )


ORDER BY d.create_time DESC
